void mainImage(out vec4 o, vec2 u) {
    // 1. INIZIALIZZAZIONE ESPLICITA (Fondamentale in Desktop GL)
    float s = 0.0;
    float i = 0.0;      // Iteratore inizializzato a 0
    float d = 0.0;      // Distanza inizializzata a 0
    float T = iTime;

    // Inizializziamo l'output (colore) a nero per sicurezza
    o = vec4(0.0);

    // 2. SETUP COORDINATE
    // Usa iResolution passata dall'uniform
    vec3 p_res = iResolution; 

    // Centra e scala le UV
    u = (u - p_res.xy * 0.5) / p_res.y;

    // Aggiungi movimento camera
    u += vec2(sin(T * 0.2) * 0.3, sin(T * 0.5) * 0.1);

    // 3. RAYMARCHING LOOP
    // Abbiamo rimosso i trucchi strani nel 'for' e reso tutto esplicito
    for(i = 0.0; i < 128.0; i++) {

        // Calcolo posizione raggio (p)
        // p = ro + rd * d (approssimato per questo shader specifico)
        vec3 p = vec3(u * d, d + T * 100.0);

        // Effetti di distorsione dello spazio (Iso lines effect)
        p.z += cos(p.z * 0.7);

        // Spostamento asse X per evitare artefatti centrali
        p.x += 100.0 - cos(T) * 10.0;

        // Turbolenza "Xor style" (flusso)
        p += cos(p.yzx / 16.0) * 16.0;

        // Funzione Gyroid: dot(sin(p), cos(p))
        // Questa è la formula che crea la forma aliena
        float gyroid = dot(sin(p / 132.0), cos(p.yzx / 64.0));

        // Calcolo distanza (Signed Distance Function)
        s = 0.005 + 0.8 * abs(32.0 * gyroid);

        // Avanza il raggio
        d += s;

        // Accumula colore (Fog/Glow effect) basato su altezza Y
        // Usiamo punti e virgola standard invece delle virgole
        vec4 colorUpdate = (1.0 + cos(0.03 * p.y + vec4(3, 1, 0, 0))) / s;
        o += colorUpdate;

        // Ottimizzazione: se siamo troppo lontani o abbiamo toccato, usciamo?
        // In questo shader artistico si lascia correre per l'effetto glow,
        // ma in uno standard si farebbe: if(d > 1000.0 || s < 0.001) break;
    }

    // 4. TONE MAPPING
    // Divide per normalizzare la luminosità accumulata e applica tanh
    o = tanh(o / 3000.0);
}

